  .then(data => {
    // Get all subdirectories (categories)
    const dirs = data.filter(d => d.type === 'dir').map(d => d.name);
    // Get first level skills by fetching each category
    return Promise.all(dirs.map(dir => 
      fetch(`https://api.github.com/repos/NousResearch/hermes-agent/contents/optional-skills/${dir}`)
        .then(r => r.json())
        .then(items => ({
          category: dir,
          skills: items.filter(i => i.type === 'dir').map(i => i.name)
        }))
    ));
  })
