{"expression": "// Fetch SKILL.md for each skill to get description
const allSkills = window.__optionalSkills;
const results = [];

async function getAllDescriptions() {
  for (const cat of allSkills) {
    for (const skill of cat.skills) {
      try {
        const r = await fetch(`https://raw.githubusercontent.com/NousResearch/hermes-agent/main/optional-skills/${cat.category}/${skill}/SKILL.md`);
        const text = await r.text();
        // Extract first line or YAML frontmatter description
        const descMatch = text.match(/description:\s*"([^"]+)"/) || text.match(/description:\s*'([^']+)'/) || text.match(/^# (.+)/m) || text.match(/\n\n(.+?)\n/);
        const desc = descMatch ? descMatch[1] : text.substring(0, 150).replace(/\n/g, ' ');
        results.push({category: cat.category, name: skill, desc: desc});
      } catch(e) {
        results.push({category: cat.category, name: skill, desc: '(description unavailable)'});
      }
    }
  }
  return results;
}

getAllDescriptions().then(res => { window.__skillDescs = res; console.log('DONE:', res.length, 'skills'); });"}
